import{c as o,a3 as c,p as d,s as i}from"./chunks/framework.BEQTiVti.js";const u=JSON.parse('{"title":"📠 更新日志","description":"","frontmatter":{},"headers":[],"relativePath":"guide/changelog.md","filePath":"guide/changelog.md","lastUpdated":1780498940000}'),a={name:"guide/changelog.md"};function t(l,e,r,s,n,p){return c(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="📠-更新日志" tabindex="-1">📠 更新日志 <a class="header-anchor" href="#📠-更新日志" aria-label="Permalink to “📠 更新日志”">​</a></h1><h2 id="_10-0-0-beta3" tabindex="-1">10.0.0-beta3 <a class="header-anchor" href="#_10-0-0-beta3" aria-label="Permalink to “10.0.0-beta3”">​</a></h2><p><code>2026-06-03</code></p><ul><li>🆕 支持自定义快捷键。</li><li>🆕 覆盖物新增连续绘制模式，内置覆盖物新增 <code>brush</code> 。</li><li>👉 调整内置指标 <code>RSI</code> 计算逻辑。</li><li>🐞 修复覆盖物锁定状态下，事件落在覆盖物上，无法滚动图表问题。</li><li>🐞 修复强制结束绘制的覆盖物，无法通过 <code>createOverlay</code> 恢复问题。</li><li>🐞 修复覆盖物弱磁模式下绘制响应问题。</li><li>🐞 修复向后加载数据，可能无限触发数据请求方法回调问题。</li><li>🐞 修复 <code>resize</code> 可能不生效问题。</li></ul><h2 id="_10-0-0-beta2" tabindex="-1">10.0.0-beta2 <a class="header-anchor" href="#_10-0-0-beta2" aria-label="Permalink to “10.0.0-beta2”">​</a></h2><p><code>2026-05-20</code></p><ul><li><p>🆕 新特性</p><ul><li>支持多 y 轴，同一窗口可以创建多个 y 轴，并通过指标的 <code>yAxisId</code> 绑定到指定 y 轴。</li><li>新增实例方法 <code>overrideXAxis(options)</code> 和 <code>overrideYAxis(options)</code> ，用于独立设置 x 轴和 y 轴配置。</li><li>图表支持容器尺寸自动监听和自动 <code>resize()</code> 。</li><li>指标图形新增 <code>text</code> 类型，指标 <code>figures</code> 可以直接绘制文本。</li></ul></li><li><p>👉 变更</p><ul><li>图表方法 <code>init(ds, options)</code> 中的 <code>options.layout</code> 由数组结构调整为对象结构，新增 <code>basicParams</code> 和 <code>panes</code> ： <ul><li><code>basicParams</code> 支持配置 <code>barSpaceLimitMin</code> ， <code>barSpaceLimitMax</code> ， <code>yAxisPosition</code> ， <code>yAxisInside</code> ， <code>paneMinHeight</code> 和 <code>paneHeight</code> 。</li><li><code>panes</code> 用于配置窗口布局，窗口内容支持通过 <code>{ indicator, yAxis }</code> 为指标指定 y 轴配置。</li></ul></li><li>实例方法 <code>createIndicator(indicator, isStack?, paneOptions?)</code> 变更为 <code>createIndicator(indicator, options?)</code> ， <code>options</code> 支持 <code>isStack</code> ， <code>pane</code> 和 <code>yAxis</code> 。</li><li><code>setPaneOptions(options)</code> 不再包含坐标轴配置，坐标轴配置请使用 <code>overrideXAxis(options)</code> 或 <code>overrideYAxis(options)</code> 。</li><li><code>convertToPixel(value, filter?)</code> 和 <code>convertFromPixel(coordinate, filter?)</code> 的 <code>filter</code> 新增 <code>yAxisId</code> 。</li></ul></li><li><p>🐞 修复实例 API <code>setZoomAnchor</code> 参数类型错误。</p></li><li><p>💄 优化构建流程，构建工具由 rollup 调整为 Vite，并新增 <code>type-check</code> 校验。</p></li></ul><h2 id="_10-0-0-beta1" tabindex="-1">10.0.0-beta1 <a class="header-anchor" href="#_10-0-0-beta1" aria-label="Permalink to “10.0.0-beta1”">​</a></h2><p><code>2025-11-21</code></p><ul><li>🆕 新特性 <ul><li>支持千分符，小数折叠自定义。</li><li>x轴支持显示未来时间。</li><li>支持在移动端y轴拖动。</li><li>支持在同一窗口上创建多个相同名称的指标。</li><li>重写坐标轴模块，自定义y轴支持设置范围。</li><li>图表方法 <code>init(dom, options)</code> 中的 <code>options</code> 新增 <code>zoomAnchor</code> 。</li><li>实例新增方法 <code>setZoomAnchor(anchor)</code> ， <code>getZoomAnchor()</code> ， <code>setDataLoader(loader)</code> ， <code>setSymbol(symbol)</code> ， <code>getSymbol()</code> ， <code>setPeriod(period)</code> ， <code>getPeriod()</code> ， <code>resetData()</code> ， <code>setThousandsSeparator(thousandsSeparator)</code> ， <code>getThousandsSeparator()</code> ， <code>setDecimalFold(decimalFold)</code> ， <code>getDecimalFold()</code> ， <code>getIndicators()</code> 和 <code>getOverlays()</code> 。</li><li>样式配置新增 <code>candle.priceMark.last.extendTexts</code> ， <code>candle.tooltip.title</code> ， <code>candle.tooltip.legend</code> ， <code>indicator.tooltip.title</code> ， <code>indicator.tooltip.legend</code> ， <code>crosshair.horizontal.features</code> ， <code>candle.bar.compareRule</code> ， <code>indicator.ohlc.compareRule</code> 和 <code>candle.priceMark.last.compareRule</code> 。</li><li>实例方法 <code>subscribeAction</code> 和 <code>unsubscribeAction</code> ， 入参 <code>type</code> 新增 <code>onIndicatorTooltipFeatureClick</code> 和 <code>onCrosshairFeatureClick</code> 。</li></ul></li><li>👉 变更 <ul><li>图表方法 <code>init(dcs, options)</code> ， <code>options.layout</code> 子项中的 <code>position</code> 变更为 <code>order</code> ， <code>options.thousandsSeparator</code> 变更为对象 <code>{ sign, format }</code> ， <code>options.decimalFoldThreshold</code> 变更为 <code>options.decimalFold</code> ， <code>options.customApi</code> 变更为 <code>options.formatter</code> ， <code>formatDate</code> 参数变更为对象。</li><li>实例方法 <code>setCustomApi</code> 变更为 <code>setFormatter</code> ， <code>getCustomApi</code> 变更为 <code>getFormatter</code> ， <code>getBarSpace()</code> 返回值变更为对象 ， <code>createIndicator</code> 返回值变更为返回指标id ， <code>overlayIndicator</code> 入参 <code>paneId</code> 合并到入参 <code>indicator</code> 中， 。</li><li>自定义指标 <code>createTooltipDataSource</code> 方法返回值 <code>values</code> 变更为 <code>legends</code> ， <code>icons</code> 变更为 <code>features</code> 。</li><li>样式配置 <code>candle.tooltip.icons</code> 变更为 <code>candle.tooltip.features</code> ， <code>indicator.tooltip.icons</code> 变更为 <code>indicator.tooltip.features</code> 。</li></ul></li><li>💄 优化 <ul><li>优化覆盖物模版中的 <code>figure</code> 忽略事件类型，事件名和 <code>overlay</code> 中的事件名称一致。</li><li>优化指标计算任务执行。</li><li>优化移动端滚动事件触发。</li></ul></li><li>🗑 废弃 <ul><li>图表方法删除 <code>utils.drawArc(ctx, arc, styles)</code> ，<code>utils.drawCircle(ctx, circle, styles)</code> ， <code>utils.drawLine(ctx, line, styles)</code> ，<code>utils.drawPolygon(ctx, polygon, styles)</code> ， <code>utils.drawRect(ctx, rect, styles)</code> ，<code>utils.drawText(ctx, text, styles)</code> ， <code>utils.drawRectText(ctx, rectText, styles)</code>，请使用 <code>getFigureClass(name)</code> 代替。</li><li>实例方法删除 <code>setPriceVolumePrecision(pricePrecision, volumePrecision)</code> ，请使用 <code>setPrecision(precision)</code> 代替。</li><li>实例api删除 <code>setLoadMoreData</code> ， <code>applyNewData</code> ， <code>updateData</code> ， 请替换为 <code>setDataLoader</code> ， 删除 <code>clearData</code> ， <code>setPrecision</code> 和 <code>getPrecision</code>。</li><li>实例方法删除 <code>getIndicatorByPaneId(paneId, name)</code> ，请使用 <code>getIndicators(filter)</code> 代替。</li><li>实例方法删除 <code>getOverlayById(id)</code> ，请使用 <code>getOverlays(filter)</code> 代替。</li><li>实例方法 <code>subscribeAction</code> 和 <code>unsubscribeAction</code> 删除入参 <code>onTooltipIconClick</code> ，请使用 <code>onCandleTooltipFeatureClick</code> 和 <code>onIndicatorTooltipFeatureClick</code> 代替。</li><li>样式配置删除 <code>yAxis.position</code> ， <code>yAxis.type</code> ， <code>yAxis.inside</code> 和 <code>yAxis.inside</code> ，请使用 <a href="/api/instance/overrideYAxis#parameters">overrideYAxis(options)</a> 代替。详情参阅图表API <a href="/api/chart/init#parameters">init(dcs, options)</a> ，实例API <a href="/api/instance/createIndicator#parameters">createIndicator(indicator, options)</a> 、 <a href="/api/instance/setPaneOptions#parameters">setPaneOptions(options)</a> 和 <a href="/api/instance/overrideYAxis#parameters">overrideYAxis(options)</a> 。</li><li>样式配置删除 <code>candle.tooltip.defaultValue</code> ， <code>candle.tooltip.custom</code> 请替换为 <code>candle.tooltip.legend</code> ，删除 <code>candle.tooltip.text</code> ，删除 <code>indicator.tooltip.showName</code> ， <code>indicator.tooltip.showParams</code> ，请用 <code>indicator.tooltip.title</code> ，删除 <code>indicator.tooltip.defaultValue</code> ， 请替换为 <code>indicator.tooltip.legend</code> ， 删除 <code>indicator.tooltip.text</code> ， 删除 <code>overlay.rectText</code> 。</li><li>内置的基础图形删除 <code>rectText</code> ，请使用 <code>text</code> 代替。</li></ul></li></ul><h2 id="_9-x" tabindex="-1">9.x <a class="header-anchor" href="#_9-x" aria-label="Permalink to “9.x”">​</a></h2><p>去 <a href="https://v9.klinecharts.com" target="_blank" rel="noreferrer">https://v9.klinecharts.com</a> 上查看。</p><h2 id="_8-x" tabindex="-1">8.x <a class="header-anchor" href="#_8-x" aria-label="Permalink to “8.x”">​</a></h2><p>去 <a href="https://v8.klinecharts.com" target="_blank" rel="noreferrer">https://v8.klinecharts.com</a> 上查看。</p><h2 id="_7-x" tabindex="-1">7.x <a class="header-anchor" href="#_7-x" aria-label="Permalink to “7.x”">​</a></h2><p>去 <a href="https://github.com/liihuu/KLineChart/blob/v7.5.0/docs/zh-CN/changelog.md" target="_blank" rel="noreferrer">Github</a> 上查看 7.x 的 Change Log。</p><h2 id="_6-x" tabindex="-1">6.x <a class="header-anchor" href="#_6-x" aria-label="Permalink to “6.x”">​</a></h2><p>去 <a href="https://github.com/liihuu/KLineChart/blob/v6.1.0/docs/zh-CN/CHANGELOG.md" target="_blank" rel="noreferrer">Github</a> 上查看 6.x 的 Change Log。</p><h2 id="_5-x" tabindex="-1">5.x <a class="header-anchor" href="#_5-x" aria-label="Permalink to “5.x”">​</a></h2><p>去 <a href="https://github.com/liihuu/KLineChart/releases/tag/v5.0.0" target="_blank" rel="noreferrer">Github</a> 上查看 5.x 的版本记录。</p><h2 id="_4-x" tabindex="-1">4.x <a class="header-anchor" href="#_4-x" aria-label="Permalink to “4.x”">​</a></h2><p>去 <a href="https://github.com/liihuu/KLineChart/releases/tag/v4.0.0" target="_blank" rel="noreferrer">Github</a> 上查看 4.x 的版本记录。</p>',22)])])}const x=o(a,[["render",t]]);export{u as __pageData,x as default};
